    public Object parseMarket(Object market)
    {
        Object id = this.safeString(market, "symbol");
        Object id2 = this.safeString(market, "crossSymbolName");
        Object quoteId = this.safeString(market, "l2PairId");
        Object baseId = this.safeString(market, "baseTokenId");
        Object quote = this.safeString(market, "settleAssetId");
        Object base = this.safeCurrencyCode(baseId);
        Object settleId = this.safeString(market, "settleAssetId");
        Object settle = this.safeCurrencyCode(settleId);
        Object symbol = Helpers.add(Helpers.add(Helpers.add(Helpers.add(baseId, "/"), quote), ":"), settle);
        Object expiry = 0;
        Object takerFee = this.parseNumber("0.0002");
        Object makerFee = this.parseNumber("0.0005");
        final Object finalBaseId = baseId;
        final Object finalExpiry = expiry;
        return this.safeMarketStructure(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "id2", id2 );
            put( "symbol", symbol );
            put( "base", base );
            put( "quote", quote );
            put( "settle", settle );
            put( "baseId", finalBaseId );
            put( "quoteId", quoteId );
            put( "settleId", settleId );
            put( "type", "swap" );
            put( "spot", false );
            put( "margin", null );
            put( "swap", true );
            put( "future", false );
            put( "option", false );
            put( "active", ApexCore.this.safeBool(market, "enableTrade") );
            put( "contract", true );
            put( "linear", true );
            put( "inverse", false );
            put( "taker", takerFee );
            put( "maker", makerFee );
            put( "contractSize", ApexCore.this.safeNumber(market, "minOrderSize") );
            put( "expiry", ((Helpers.isTrue((Helpers.isEqual(finalExpiry, 0))))) ? null : finalExpiry );
            put( "expiryDatetime", ((Helpers.isTrue((Helpers.isEqual(finalExpiry, 0))))) ? null : ApexCore.this.iso8601(finalExpiry) );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", ApexCore.this.safeNumber(market, "stepSize") );
                put( "price", ApexCore.this.safeNumber(market, "tickSize") );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "min", ApexCore.this.safeNumber(market, "displayMinLeverage") );
                    put( "max", ApexCore.this.safeNumber(market, "displayMaxLeverage") );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", ApexCore.this.safeNumber(market, "minOrderSize") );
                    put( "max", ApexCore.this.safeNumber(market, "maxOrderSize") );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "created", null );
            put( "info", market );
        }});
    }

