            put( "timeInForce", ApexCore.this.parseTimeInForce(ApexCore.this.safeString(order, "timeInForce")) );
            put( "postOnly", ApexCore.this.safeBool(order, "postOnly") );
            put( "reduceOnly", ApexCore.this.safeBool(order, "reduceOnly") );
